ConstellationMgr.setFlagArt(true);
ConstellationMgr.setFlagArt(false);

var current = ConstellationMgr.getFlagArt();
ConstellationMgr.setFlagArt(!current);

ConstellationMgr.setArtFadeDuration(0.5);
ConstellationMgr.setFlagArt(true);

var fade = ConstellationMgr.getArtFadeDuration();
core.debug("Fade duration: " + fade);

ConstellationMgr.setArtIntensity(1.0);
ConstellationMgr.setArtIntensity(0.5);

var intensity = ConstellationMgr.getArtIntensity();
core.debug("Art intensity: " + intensity);

ConstellationMgr.setArtIntensityMinimumFov(0.5);
ConstellationMgr.setArtIntensityMaximumFov(2.0);

var minFov = ConstellationMgr.getArtIntensityMinimumFov();
core.debug("Art min FOV: " + minFov);

var red = core.vec3f(1.0, 0.0, 0.0);
ConstellationMgr.setBoundariesColor(red);

var color = ConstellationMgr.getBoundariesColor();
core.debug("Boundaries color: RGB" + color);

if(ConstellationMgr.getFlagConstellationPick()) {
    core.debug("Single constellation pick mode is on");
}

var cyan = core.vec3f(0.0, 0.8, 0.9);
ConstellationMgr.setLinesColor(cyan);

var color = ConstellationMgr.getLinesColor();
core.debug("Lines color: RGB" + color);

var white = core.vec3f(1.0, 1.0, 1.0);
ConstellationMgr.setLabelsColor(white);

var color = ConstellationMgr.getLabelsColor();
core.debug("Labels color: RGB" + color);

ConstellationMgr.setFontSize(18);
ConstellationMgr.setFontSize(15);

var fontSize = ConstellationMgr.getFontSize();
core.debug("Font size: " + fontSize);

var red = core.vec3f(1.0, 0.0, 0.0);
ConstellationMgr.setHullsColor(red);

var color = ConstellationMgr.getHullsColor();

var gold = core.vec3f(1.0, 0.84, 0.0);
ConstellationMgr.setZodiacColor(gold);

var color = ConstellationMgr.getZodiacColor();

ConstellationMgr.setFlagZodiac(true);
ConstellationMgr.setFlagZodiac(false);

if(ConstellationMgr.getFlagZodiac()) {
    core.debug("Zodiac is visible");
}

var cyan = core.vec3f(0.0, 1.0, 0.5);
ConstellationMgr.setLunarSystemColor(cyan);

var color = ConstellationMgr.getLunarSystemColor();

var constellations = ConstellationMgr.getConstellationsEnglishNames();
core.debug("Total constellations: " + constellations.length);

for(var i=0; i<Math.min(5, constellations.length); i++) {
    core.debug((i+1) + ". " + constellations[i]);
}

var fullName = ConstellationMgr.getIAUconstellationName("Ori");
core.debug("Ori = " + fullName);

var umaName = ConstellationMgr.getIAUconstellationName("UMa");
core.debug("UMa = " + umaName);

ConstellationMgr.starsInHullOf("Orion", true, 6.0, "orion_stars");
core.debug("Orion stars exported to CSV");

ConstellationMgr.starsInHullOf("Ursa Major", false, 25.0, "ursa_major_stars");
